FROM jsonb_to_recordset('[{"id": "cap-108-chinese-015", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「我向默默耕耘者學習等待，也向堅持不懈者學習勇敢；我從高傲的人身上學會\n了彎腰，也從奢靡的人身上學到了簡樸。」這段文句最能呼應《論語》中的哪\n一段話？", "options": ["學而時習之，不亦說乎", "人之過也，各於其黨。觀過，斯知仁矣", "三人行，必有我師焉。擇其善者而從之，其不善者而改之", "君子不重則不威，學則不固。主忠信。無友不如己者。過則勿憚改"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 15, "raw_text": "15. 「我向默默耕耘者學習等待，也向堅持不懈者學習勇敢；我從高傲的人身上學會\n    了彎腰，也從奢靡的人身上學到了簡樸。」這段文句最能呼應《論語》中的哪\n    一段話？\n    (A)學而時習之，不亦說乎\n    (B)人之過也，各於其黨。觀過，斯知仁矣\n    (C)三人行，必有我師焉。擇其善者而從之，其不善者而改之\n    (D)君子不重則不威，學則不固。主忠信。無友不如己者。過則勿憚改\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-016", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列文句，何者有冗言贅字？", "options": ["他向來喜歡在政論節目裡高談闊論", "張伯伯樂善好施，在鄉里間傳為美談", "小陳擅長能言善道，常幫朋友排解糾紛", "證據顯示，他是這件縱火案的頭號嫌疑犯"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 16, "raw_text": "16. 下列文句，何者有冗言贅字？\n    (A)他向來喜歡在政論節目裡高談闊論\n    (B)張伯伯樂善好施，在鄉里間傳為美談\n    (C)小陳擅長能言善道，常幫朋友排解糾紛\n    (D)證據顯示，他是這件縱火案的頭號嫌疑犯\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-017", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「若不撇開終是苦，各能捺住即成名。」關於這副對聯，下列說明何者正確？", "options": ["上聯意謂人生苦短，應及時努力", "下聯勉人要看破功名，隨遇而安", "上、下聯的末字刻意不合平仄，以擴展意境", "由「若」「苦」、「各」「名」的字形差異發想"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17. 「若不撇開終是苦，各能捺住即成名。」關於這副對聯，下列說明何者正確？\n    (A)上聯意謂人生苦短，應及時努力\n    (B)下聯勉人要看破功名，隨遇而安\n    (C)上、下聯的末字刻意不合平仄，以擴展意境\n    (D)由「若」「苦」、「各」「名」的字形差異發想\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-018", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "關於這則請柬，下列敘述何者正確？", "options": ["「家嚴」應改為「令尊」", "「聖誕」應改為「壽誕」", "「桃樽」應改為「桃符」", "「謹稟」應改為「叩首」"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18.\n\n\n\n\n      關於這則請柬，下列敘述何者正確？\n      (A)「家嚴」應改為「令尊」 (B)「聖誕」應改為「壽誕」\n      (C)「桃樽」應改為「桃符」 (D)「謹稟」應改為「叩首」\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-019", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「學書之法，初學分布，但求平正；既知平正，務追險絕；既能險絕，復歸平正。\n初謂未及，中則過之，後乃通會。」這段話的寫作用意，最可能是下列何者？", "options": ["說明學習書法的不同階段與進境", "強調練習書法時要有正確的心態", "提醒常人不應追求艱難的書法技巧", "指出書法的最高境界在於標新立異"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 19, "raw_text": "19. 「學書之法，初學分布，但求平正；既知平正，務追險絕；既能險絕，復歸平正。\n    初謂未及，中則過之，後乃通會。」這段話的寫作用意，最可能是下列何者？\n    (A)說明學習書法的不同階段與進境\n    (B)強調練習書法時要有正確的心態\n    (C)提醒常人不應追求艱難的書法技巧\n    (D)指出書法的最高境界在於標新立異\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-020", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "藍水溪是青水溪最大的支流，它有三條支流，最大支流瓦里蘭溪發源自\n初雲風景區，上、下游海拔落差達1500公尺，由東向西行，沿路形成乾坤峽\n谷等特殊景點，溪水來到日月鎮 光明里，匯進藍水溪。另兩條支流皆發源於\n高土山北麓，在依蘇坪相匯。洛瑪颱風之後，沿瓦里蘭溪河谷，多處著名觀\n光景點被強大洪水更動了原貌，著名的乾坤峽谷也被沖毀變形。\n右圖顯示藍水溪及其支流的位置。根據上述文字，\n圖中甲～丁的標示何者正確？", "options": ["甲：初雲風景區", "乙：高土山", "丙︰光明里", "丁：依蘇坪"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 20, "raw_text": "20.\n        藍水溪是青水溪最大的支流，它有三條支流，最大支流瓦里蘭溪發源自\n      初雲風景區，上、下游海拔落差達1500公尺，由東向西行，沿路形成乾坤峽\n      谷等特殊景點，溪水來到日月鎮 光明里，匯進藍水溪。另兩條支流皆發源於\n      高土山北麓，在依蘇坪相匯。洛瑪颱風之後，沿瓦里蘭溪河谷，多處著名觀\n      光景點被強大洪水更動了原貌，著名的乾坤峽谷也被沖毀變形。\n\n      右圖顯示藍水溪及其支流的位置。根據上述文字，\n      圖中甲～丁的標示何者正確？\n      (A)甲：初雲風景區\n      (B)乙：高土山\n      (C)丙︰光明里\n      (D)丁：依蘇坪\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-021", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列選項「」中的字，何者字義前後相同？", "options": ["人「微」言輕／出身寒「微」", "洞「悉」真相／「悉」數帶回", "茂林「修」竹／「修」築道路", "探本「窮」源／一「窮」二白"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21.   下列選項「」中的字，何者字義前後相同？\n      (A)人「微」言輕／出身寒「微」\n      (B)洞「悉」真相／「悉」數帶回\n      (C)茂林「修」竹／「修」築道路\n      (D)探本「窮」源／一「窮」二白\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-022", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「諸葛武侯文采不豔，然其〈出師〉二表至今為學者膾炙，有志之士擊節讀之，\n有至於嗟嘆流涕者。六朝、隋、唐文人動輒百數十篇，穠華纖巧，極其雕飾，\n或卒無一語可傳。然則文之為文，豈必多且麗乎哉？」根據這段文字，下列何\n者最符合作者的觀點？", "options": ["文章之優劣，取決於作者的學識修養與文采表現", "寫作不宜過度雕章琢句，當以抒發情志、感動人心為佳", "六朝文人多投注心力於雕飾辭藻，以致作品質精而量少", "諸葛武侯文采不豔，唯〈出師〉二表典麗華美，膾炙人口"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 22, "raw_text": "22. 「諸葛武侯文采不豔，然其〈出師〉二表至今為學者膾炙，有志之士擊節讀之，\n    有至於嗟嘆流涕者。六朝、隋、唐文人動輒百數十篇，穠華纖巧，極其雕飾，\n    或卒無一語可傳。然則文之為文，豈必多且麗乎哉？」根據這段文字，下列何\n    者最符合作者的觀點？\n    (A)文章之優劣，取決於作者的學識修養與文采表現\n    (B)寫作不宜過度雕章琢句，當以抒發情志、感動人心為佳\n    (C)六朝文人多投注心力於雕飾辭藻，以致作品質精而量少\n    (D)諸葛武侯文采不豔，唯〈出師〉二表典麗華美，膾炙人口\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-023", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "金陵城北有湖，名園勝境，掩映如畫。一日，諸臣待漏1朝堂，語及林泉之\n事，坐間馮謐舉唐玄宗賜賀知章三百里鏡湖，曰：「予非敢望此，但賜後湖，\n亦暢予平生也。」吏部徐鉉怡聲而對曰：「主上尊賢待士，常恐不及，豈惜一後\n湖？所乏者知章爾。」馮大有慚色。\n根據本文，下列敘述何者正確？\n", "options": ["徐鉉覺得馮謐之才不及賀知章      1.待漏：古群臣聽漏刻入朝，", "徐鉉安慰馮謐他日終將獲得賞賜          後用以比喻將入朝時", "徐鉉認為三百里鏡湖應賞賜給馮謐", "徐鉉暗示馮謐應知所進退、歸隱山林"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 23, "raw_text": "23.     金陵城北有湖，名園勝境，掩映如畫。一日，諸臣待漏1朝堂，語及林泉之\n      事，坐間馮謐舉唐玄宗賜賀知章三百里鏡湖，曰：「予非敢望此，但賜後湖，\n      亦暢予平生也。」吏部徐鉉怡聲而對曰：「主上尊賢待士，常恐不及，豈惜一後\n      湖？所乏者知章爾。」馮大有慚色。\n      根據本文，下列敘述何者正確？\n                            \n      (A)徐鉉覺得馮謐之才不及賀知章      1.待漏：古群臣聽漏刻入朝，\n      (B)徐鉉安慰馮謐他日終將獲得賞賜          後用以比喻將入朝時\n      (C)徐鉉認為三百里鏡湖應賞賜給馮謐\n      (D)徐鉉暗示馮謐應知所進退、歸隱山林\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-024", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "某古物專家在電視上介紹著：「這一件應該是商、周時代的文物，是一種三\n足、兩耳、刻有精細紋飾的青銅器。上面還有幾個字……。」根據描述，這\n個器物上的文字應該被稱為什麼？", "options": ["小篆", "金文", "隸書", "甲骨文"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 24, "raw_text": "24. 某古物專家在電視上介紹著：「這一件應該是商、周時代的文物，是一種三\n    足、兩耳、刻有精細紋飾的青銅器。上面還有幾個字……。」根據描述，這\n    個器物上的文字應該被稱為什麼？\n    (A)小篆   (B)金文   (C)隸書    (D)甲骨文\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-025", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的詞語，何者使用最恰當？", "options": ["小民氣度雍容，「櫛風沐雨」的胸襟令人景仰", "小軍老是搞不清狀況，「越俎代庖」管他人閒事", "玉山交響樂團的演奏氣勢雄渾，聽者「肝腸寸斷」", "阿國抱持「笨鳥先飛」的心態，見利總要搶得先機"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 25, "raw_text": "25. 下列文句「」中的詞語，何者使用最恰當？\n    (A)小民氣度雍容，「櫛風沐雨」的胸襟令人景仰\n    (B)小軍老是搞不清狀況，「越俎代庖」管他人閒事\n    (C)玉山交響樂團的演奏氣勢雄渾，聽者「肝腸寸斷」\n    (D)阿國抱持「笨鳥先飛」的心態，見利總要搶得先機\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-026", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「宣紙有生熟之別，互有利弊，各隨所好而已。生紙易滲水墨，筆頭水分要控\n制得宜，於溼乾濃淡之間顯出揮灑的韻味。嘗見有人作畫，急欲獲致水墨滲渲\n的效果，不斷的以口吮毫，一幅畫成，舌面盡黑。工筆畫，正楷書，皆宜熟\n紙。不過亦不盡然，我看見過徐青藤花卉冊頁的複製品，看那淋漓的水渲墨\n暈，不像是熟紙。」根據這段文字，下列推論何者錯誤？", "options": ["寫正楷書的時候，不宜使水墨滲渲", "作者推測徐青藤可能是用生紙來畫花卉", "作者所見以口吮毫之人，應是在畫工筆畫", "在生宣紙上控制筆頭水分，要比在熟紙困難"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 26, "raw_text": "26. 「宣紙有生熟之別，互有利弊，各隨所好而已。生紙易滲水墨，筆頭水分要控\n     制得宜，於溼乾濃淡之間顯出揮灑的韻味。嘗見有人作畫，急欲獲致水墨滲渲\n     的效果，不斷的以口吮毫，一幅畫成，舌面盡黑。工筆畫，正楷書，皆宜熟\n     紙。不過亦不盡然，我看見過徐青藤花卉冊頁的複製品，看那淋漓的水渲墨\n     暈，不像是熟紙。」根據這段文字，下列推論何者錯誤？\n     (A)寫正楷書的時候，不宜使水墨滲渲\n     (B)作者推測徐青藤可能是用生紙來畫花卉\n     (C)作者所見以口吮毫之人，應是在畫工筆畫\n     (D)在生宣紙上控制筆頭水分，要比在熟紙困難\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-027", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "趙簡子問於壯馳茲曰：「東方之士孰為愈1？」壯馳茲曰：「敢賀！」簡子\n曰：「未應吾問，何賀？」對曰：「臣聞之：國家將興也，君子自以為不足；\n其亡也，若有餘。今子任晉國之政，而問及小人，又求賢人，吾是以賀。」\n根據這段文字，趙簡子之所以得到壯馳茲的祝賀，\n\n其原因最可能是下列何者？\n1.愈：高明", "options": ["取得晉國執政權", "能明辨小人與賢人", "具備禮賢下士的態度", "已找到東方最好的謀士"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 27, "raw_text": "27.\n        趙簡子問於壯馳茲曰：「東方之士孰為愈1？」壯馳茲曰：「敢賀！」簡子\n      曰：「未應吾問，何賀？」對曰：「臣聞之：國家將興也，君子自以為不足；\n      其亡也，若有餘。今子任晉國之政，而問及小人，又求賢人，吾是以賀。」\n\n      根據這段文字，趙簡子之所以得到壯馳茲的祝賀，\n                                    \n      其原因最可能是下列何者？\n                                    1.愈：高明\n      (A)取得晉國執政權\n      (B)能明辨小人與賢人\n      (C)具備禮賢下士的態度\n      (D)已找到東方最好的謀士\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-028", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「君子不以口譽人，則民盡忠勸善。故君子問人之寒則衣之，問人之飢則食之，\n稱人之美則爵1之。」由這段話可知，為政者對待人民的原則應是下列何者？", "options": ["循循善誘的教化 ", "公平公正的賞罰                 1.爵：予以官位", "無微不至的關懷", "具體實惠的行動"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 28, "raw_text": "28. 「君子不以口譽人，則民盡忠勸善。故君子問人之寒則衣之，問人之飢則食之，\n    稱人之美則爵1之。」由這段話可知，為政者對待人民的原則應是下列何者？\n    (A)循循善誘的教化\n                               \n    (B)公平公正的賞罰                 1.爵：予以官位\n    (C)無微不至的關懷\n    (D)具體實惠的行動\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
